using BotFramework.Discord.Commands;using BotFramework.Discord.Routing;using Games.Transfer.Application.Services;
namespace Games.Transfer.Discord;
public sealed class TransferDiscordHandler(ITransferService service):IDiscordMessageHandler{public bool CanHandle(DiscordMessageContext c)=>DiscordCommand.Is(c,"transfer");public async Task HandleAsync(DiscordMessageContext c){var p=DiscordCommand.Parts(c);var target=c.Message.MentionedUsers.FirstOrDefault();if(target is null||p.Length<2||!int.TryParse(p[^1],out var amount)||amount<=0){await DiscordCommand.ReplyAsync(c,"Использование: `transfer @user <amount>`");return;}var r=await service.TryTransferAsync(DiscordCommand.UserId(c),checked((long)target.Id),DiscordCommand.ScopeId(c),DiscordCommand.DisplayName(c),target.GlobalName??target.Username,amount,DiscordCommand.SourceId(c),c.CancellationToken);await DiscordCommand.ReplyResultAsync(c,r,"Transfer");}}
public static class TransferDiscordModule{public static IServiceCollection AddTransferDiscord(this IServiceCollection s)=>s.AddScoped<IDiscordMessageHandler,TransferDiscordHandler>();}
